example.code:
# After user selects variant N
chosen_dir = f"designs/variant-{N}-{slug}"
Task(
    subagent_type="faion-frontend-brainstormer-agent",
    prompt=f"""Refine {chosen_dir} based on feedback: {user_feedback}

Original spec: {requirements}
Constraint: only edit files inside {chosen_dir}.
Do NOT modify globals.css or tailwind.config yet.
Deliver updated runnable preview + diff vs previous iteration."""
)
